html:xslt.xsl:template:
			function showFinished(value){
var finalizadas;
if(value){
finalizadas = 1;
}else{
finalizadas = 0;
}

var dir;

dir = "../../../ReportViewer.aspx?";
dir = dir + "report={#PROXY.APP#}.NucleusRH.Base.Personal.InstanciasWF.GEN.GADGET";
dir = dir + "{#CHAR.AMP#}finalizadas=" + finalizadas;


document.location = dir;
return true;
}

			div#content-instancesWF{
width: 100%;
}

label#show-finished{
margin-right: 5px;
color: #3085b8;
//text-decoration: underline;
margin-left: 0.5rem;
font-size: 14px;
font-weight: 600;
}

thead.mis-solicitudes{
background-color: #006E8C;
color: white;
height: 30px;
font-size: 14px;
font-weight: 600;
}

#table-mis-solicitudes{
border-collapse: collapse;
border: none;
width: 100%;
}

span.cell_style_1{
color: #2a2a2a;
font-size: 12px;
font-weight: 600;
}

#table-mis-solicitudes tbody tr, #table-mis-solicitudes tfoot tr{
background-color: #f3f3f3;	
}

#table-mis-solicitudes tbody tr.finalizada{
background-color: #F2DEDE;	
}

#table-mis-solicitudes tbody tr.guardada{
background-color: #D4EDDA;	
}

#table-mis-solicitudes thead tr td, #table-mis-solicitudes tbody tr td, #table-mis-solicitudes tfoot tr td{
padding-left: 10px;
padding-right: 10px;
text-align: center;
} 

#table-mis-solicitudes tbody tr:hover{		
background-color: #fefefe;
cursor: pointer;
}

.pointer{
cursor:pointer;
}

.tabla_detail div {
  clear: none;
  font-size: 11px;
  font-weight: normal;
  color: #303030;
  text-decoration: none;
  padding-top: 5px;
  padding-bottom: 8px;
  padding-left: 3px;

  overflow:auto;
  overflow-x:none;
  overflow-y:auto;
  height:auto;
  width:auto;

  scrollbar-highlight-color:#EAEAEA;
  scrollbar-darkshadow-color:#EAEAEA;
  scrollbar-track-color:#FAFAFA;
  scrollbar-face-color:#FAFAFA;
  scrollbar-base-color:#f7f7f7;

  scrollbar-arrow-color:#8FB8C4;
}
